/*
Tabla: TRANSACCIONES_FINANCIERAS
Descripcion: Registra transacciones bancarias simuladas con informacion de clientes, montos, horarios y sucursales.

Columnas:
CODIGO_TRANSACCION - Identificador unico de la transaccion (clave primaria).
CODIGO_CLIENTE     - Numero que identifica al cliente.
HORARIO            - Turno en que se realizo la transaccion (Diurno/Vespertino/Nocturno).
MONTO              - Cantidad de dinero de la transaccion.
TIPO_TRANSACCION   - Tipo de operacion (Inversion/Prostamo/Ahorro/Tarjeta).
CODIGO_SUCURSAL    - Identificador de la sucursal bancaria.
NOMBRE_CLIENTE     - Nombre completo del cliente.
FECHA              - Fecha en que se realizo la transaccion.
*/

CREATE TABLE TRANSACCIONES_FINANCIERAS (
  CODIGO_TRANSACCION NUMBER GENERATED ALWAYS AS IDENTITY NOT NULL,
  CODIGO_CLIENTE     NUMBER NOT NULL,
  HORARIO            VARCHAR2(10) NOT NULL,
  MONTO              NUMBER(18,2) NOT NULL,
  TIPO_TRANSACCION   VARCHAR2(20) NOT NULL,
  CODIGO_SUCURSAL    VARCHAR2(20) NOT NULL,
  NOMBRE_CLIENTE     VARCHAR2(50) NOT NULL,
  FECHA              DATE NOT NULL,
  CONSTRAINT PK_CODIGO_TRANSACCION PRIMARY KEY(CODIGO_TRANSACCION),
  CONSTRAINT CK_HORARIO CHECK (HORARIO IN ('Diurno', 'Vespertino', 'Nocturno')),
  CONSTRAINT CK_TIPO_TRANSACCION CHECK (TIPO_TRANSACCION IN ('Inversion', 'Prestamo', 'Ahorro', 'Tarjeta')),
  CONSTRAINT CK_MONTO CHECK (MONTO > 0)
);


COMMIT;
